async function storageSave(data) {
  try {
    await fetch(`${SUPABASE_URL}/rest/v1/reforma_dados?id=eq.principal`, {
      method: "PATCH",
      headers: { "Content-Type": "application/json", "apikey": SUPABASE_KEY, "Authorization": `Bearer ${SUPABASE_KEY}` },
      body: JSON.stringify({ dados: data, atualizado_em: new Date().toISOString() })
    });
  } catch (_) {}
  try { localStorage.setItem(STORAGE_KEY, JSON.stringify(data)); } catch (_) {}
}
async function storageLoad() {
  try {
    const r = await fetch(`${SUPABASE_URL}/rest/v1/reforma_dados?id=eq.principal&select=dados`, {
      headers: { "apikey": SUPABASE_KEY, "Authorization": `Bearer ${SUPABASE_KEY}` }
    });
    const json = await r.json();
    if (json?.[0]?.dados && Object.keys(json[0].dados).length > 0) return json[0].dados;
  } catch (_) {}
  try { const r = localStorage.getItem(STORAGE_KEY); if (r) return JSON.parse(r); } catch (_) {}
  return null;
}
async function storageClear() {
  try {
    await fetch(`${SUPABASE_URL}/rest/v1/reforma_dados?id=eq.principal`, {
      method: "PATCH",
      headers: { "Content-Type": "application/json", "apikey": SUPABASE_KEY, "Authorization": `Bearer ${SUPABASE_KEY}` },
      body: JSON.stringify({ dados: {}, atualizado_em: new Date().toISOString() })
    });
  } catch (_) {}
  try { localStorage.removeItem(STORAGE_KEY); } catch (_) {}
}

