function ProgressBar({ pct }) {
  const c = pct > 1 ? "#ef4444" : pct > 0.9 ? "#f59e0b" : pct > 0 ? "#3b82f6" : "#e5e7eb";
  return (
    <div style={{ background: "#e5e7eb", borderRadius: 99, height: 7, overflow: "hidden", width: "100%" }}>
      <div style={{ width: `${Math.min(pct*100,100)}%`, background: c, height: "100%", borderRadius: 99, transition: "width 0.4s" }} />
    </div>
  );
}

function Badge({ n }) {
  if (n === 0) return <span style={{ fontSize: 11, color: "#9ca3af", background: "#f3f4f6", padding: "2px 8px", borderRadius: 99 }}>Não iniciado</span>;
  return <span style={{ fontSize: 11, color: "#fff", background: "#3b82f6", padding: "2px 8px", borderRadius: 99 }}>{n} lançamento{n !== 1 ? "s" : ""}</span>;
}

function Toast({ msg, onClose }) {
  useEffect(() => { const t = setTimeout(onClose, 2800); return () => clearTimeout(t); }, []);
  return (
    <div style={{ position: "fixed", bottom: 28, left: "50%", transform: "translateX(-50%)", background: "#1e293b", color: "#fff", padding: "11px 22px", borderRadius: 99, fontSize: 13, fontWeight: 600, zIndex: 9999, boxShadow: "0 4px 16px rgba(0,0,0,0.18)", display: "flex", alignItems: "center", gap: 10, whiteSpace: "nowrap" }}>
      <span style={{ color: "#86efac" }}>✓</span> {msg}
    </div>
  );
}

