function BackupModal({ json, onClose }) {
  const [status, setStatus] = useState("idle"); // idle | copied | selected
  const taRef = useRef();

  function handleCopy() {
    // Tenta clipboard API primeiro
    if (navigator.clipboard && navigator.clipboard.writeText) {
      navigator.clipboard.writeText(json)
        .then(() => { setStatus("copied"); setTimeout(() => setStatus("idle"), 2500); })
        .catch(() => fallbackSelect());
    } else {
      fallbackSelect();
    }
  }

  function fallbackSelect() {
    // Fallback: seleciona todo o texto no textarea para o usuário copiar com Ctrl+C
    if (taRef.current) {
      taRef.current.focus();
      taRef.current.select();
      try {
        document.execCommand("copy");
        setStatus("copied");
        setTimeout(() => setStatus("idle"), 2500);
      } catch (_) {
        setStatus("selected");
      }
    }
  }

  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.45)", zIndex: 9998, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
      <div style={{ background: "#fff", borderRadius: 16, padding: "24px", maxWidth: 560, width: "100%", boxShadow: "0 8px 32px rgba(0,0,0,0.2)" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 14 }}>
          <div style={{ fontWeight: 700, fontSize: 16, color: "#1e293b" }}>📋 Backup dos dados</div>
          <button onClick={onClose} style={{ background: "none", border: "none", fontSize: 18, cursor: "pointer", color: "#94a3b8" }}>✕</button>
        </div>
        <div style={{ fontSize: 12, color: "#64748b", marginBottom: 10 }}>
          Clique em <strong>Copiar tudo</strong> e cole num bloco de notas. Salve como <code>backup.txt</code> para guardar.
        </div>
        {status === "selected" && (
          <div style={{ background: "#fef9c3", border: "1px solid #fde047", borderRadius: 8, padding: "8px 12px", fontSize: 12, color: "#713f12", marginBottom: 10 }}>
            Texto selecionado! Pressione <strong>Ctrl+C</strong> para copiar.
          </div>
        )}
        <textarea
          ref={taRef}
          readOnly
          value={json}
          style={{ width: "100%", height: 200, fontFamily: "monospace", fontSize: 11, border: "1.5px solid #e2e8f0", borderRadius: 8, padding: 10, boxSizing: "border-box", resize: "none", color: "#334155", background: "#f8fafc" }}
        />
        <div style={{ display: "flex", gap: 10, marginTop: 12 }}>
          <button onClick={handleCopy} style={{ flex: 1, background: status === "copied" ? "#dcfce7" : "#2e6da4", color: status === "copied" ? "#16a34a" : "#fff", border: "none", borderRadius: 8, padding: "10px 0", fontWeight: 700, fontSize: 14, cursor: "pointer", transition: "background 0.2s" }}>
            {status === "copied" ? "✓ Copiado!" : status === "selected" ? "Ctrl+C para copiar" : "Copiar tudo"}
          </button>
          <button onClick={onClose} style={{ background: "#f1f5f9", color: "#475569", border: "none", borderRadius: 8, padding: "10px 20px", fontWeight: 600, fontSize: 14, cursor: "pointer" }}>Fechar</button>
        </div>
      </div>
    </div>
  );
}

function ImportModal({ onImport, onClose }) {
  const [text, setText] = useState("");
  const [err, setErr] = useState("");

  function handleImport() {
    setErr("");
    try {
      const raw = text.replace(/^\uFEFF/, "").trim();
      const match = raw.match(/\{[\s\S]*\}/);
      if (!match) throw new Error("JSON não encontrado");
      const parsed = JSON.parse(match[0]);
      if (!parsed.andares && !parsed.preObra && !parsed.pedreiro) throw new Error("Estrutura inválida");
      onImport(parsed);
    } catch (e) {
      setErr("Conteúdo inválido — verifique se você colou o JSON correto.");
    }
  }

  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.45)", zIndex: 9998, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
      <div style={{ background: "#fff", borderRadius: 16, padding: "24px", maxWidth: 560, width: "100%", boxShadow: "0 8px 32px rgba(0,0,0,0.2)" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 14 }}>
          <div style={{ fontWeight: 700, fontSize: 16, color: "#1e293b" }}>⬆ Importar backup</div>
          <button onClick={onClose} style={{ background: "none", border: "none", fontSize: 18, cursor: "pointer", color: "#94a3b8" }}>✕</button>
        </div>
        <div style={{ fontSize: 12, color: "#64748b", marginBottom: 10 }}>
          Cole aqui o JSON do seu backup (exportado com o botão <strong>Exportar backup</strong>).
        </div>
        {err && (
          <div style={{ background: "#fee2e2", border: "1px solid #fca5a5", borderRadius: 8, padding: "8px 12px", fontSize: 12, color: "#b91c1c", marginBottom: 10 }}>
            {err}
          </div>
        )}
        <textarea
          autoFocus
          value={text}
          onChange={e => { setText(e.target.value); setErr(""); }}
          placeholder='Cole o JSON aqui... {"andares":[...],"preObra":[...],"pedreiro":{...}}'
          style={{ width: "100%", height: 220, fontFamily: "monospace", fontSize: 11, border: "1.5px solid #e2e8f0", borderRadius: 8, padding: 10, boxSizing: "border-box", resize: "none", color: "#334155", background: "#f8fafc" }}
        />
        <div style={{ display: "flex", gap: 10, marginTop: 12 }}>
          <button
            onClick={handleImport}
            disabled={!text.trim()}
            style={{ flex: 1, background: text.trim() ? "#2e6da4" : "#cbd5e1", color: "#fff", border: "none", borderRadius: 8, padding: "10px 0", fontWeight: 700, fontSize: 14, cursor: text.trim() ? "pointer" : "default" }}
          >
            Importar dados
          </button>
          <button onClick={onClose} style={{ background: "#f1f5f9", color: "#475569", border: "none", borderRadius: 8, padding: "10px 20px", fontWeight: 600, fontSize: 14, cursor: "pointer" }}>Cancelar</button>
        </div>
      </div>
    </div>
  );
}

