const labelStyle = { fontSize: 12, fontWeight: 600, color: "#475569", marginBottom: 4, display: "block" };
const btnPrimary = { background: "#2e6da4", color: "#fff", border: "none", borderRadius: 8, padding: "10px 20px", fontWeight: 600, fontSize: 14, cursor: "pointer" };
const btnSec     = { background: "#f1f5f9", color: "#475569", border: "none", borderRadius: 8, padding: "10px 20px", fontWeight: 600, fontSize: 14, cursor: "pointer" };
const btnDanger  = { background: "#fee2e2", color: "#ef4444", border: "none", borderRadius: 6, padding: "4px 10px", fontSize: 12, cursor: "pointer" };
const btnGhost   = { background: "transparent", color: "#fff", border: "1.5px solid rgba(255,255,255,0.4)", borderRadius: 8, padding: "8px 14px", fontWeight: 600, fontSize: 12, cursor: "pointer" };

function FormGasto({ tipos, onSalvar, onCancelar, ambientes }) {
  const [g, setG] = useState({ descricao: "", tipo: tipos[0], ambiente: ambientes ? ambientes[0] : "", fornecedor: "", qtd: "", valor: "" });
  return (
    <div style={{ background: "#f8fafc", borderRadius: 10, padding: 16, marginBottom: 16, border: "1.5px solid #e2e8f0" }}>
      <div style={{ display: "grid", gridTemplateColumns: ambientes ? "1fr 1fr 1fr" : "1fr 1fr", gap: 12 }}>
        <div style={{ gridColumn: "1 / -1" }}>
          <label style={labelStyle}>Descrição *</label>
          <input style={inputStyle} placeholder="Ex: Pagamento parcela pedreiro" value={g.descricao} onChange={e => setG(p => ({ ...p, descricao: e.target.value }))} />
        </div>
        {ambientes && (
          <div>
            <label style={labelStyle}>Ambiente</label>
            <select style={inputStyle} value={g.ambiente} onChange={e => setG(p => ({ ...p, ambiente: e.target.value }))}>
              {ambientes.map(a => <option key={a}>{a}</option>)}
            </select>
          </div>
        )}
        <div>
          <label style={labelStyle}>Tipo</label>
          <select style={inputStyle} value={g.tipo} onChange={e => setG(p => ({ ...p, tipo: e.target.value }))}>
            {tipos.map(t => <option key={t}>{t}</option>)}
          </select>
        </div>
        <div>
          <label style={labelStyle}>Fornecedor / Responsável</label>
          <input style={inputStyle} placeholder="Ex: João Pedreiro" value={g.fornecedor} onChange={e => setG(p => ({ ...p, fornecedor: e.target.value }))} />
        </div>
        <div>
          <label style={labelStyle}>Qtd / Unidade</label>
          <input style={inputStyle} placeholder="Ex: 1 nota" value={g.qtd} onChange={e => setG(p => ({ ...p, qtd: e.target.value }))} />
        </div>
        <div>
          <label style={labelStyle}>Valor (R$) *</label>
          <input style={inputStyle} placeholder="Ex: 1500" value={g.valor} onChange={e => setG(p => ({ ...p, valor: e.target.value }))} />
        </div>
      </div>
      <div style={{ display: "flex", gap: 8, marginTop: 14 }}>
        <button style={btnPrimary} onClick={() => {
          if (!g.descricao || !g.valor) return;
          onSalvar({ ...g, id: Date.now(), data: new Date().toLocaleDateString("pt-BR"), valor: parseFloat(g.valor.replace(",", ".")) });
        }}>Salvar</button>
        <button style={btnSec} onClick={onCancelar}>Cancelar</button>
      </div>
    </div>
  );
}

function ListaGastos({ gastos, onRemover }) {
  if (gastos.length === 0)
    return <div style={{ textAlign: "center", color: "#94a3b8", fontSize: 13, padding: "20px 0" }}>Nenhum lançamento ainda.</div>;
  return gastos.map(g => (
    <div key={g.id} style={{ display: "flex", alignItems: "center", gap: 12, padding: "11px 0", borderBottom: "1px solid #f1f5f9" }}>
      <div style={{ flex: 1, minWidth: 0 }}>
        <div style={{ fontWeight: 600, fontSize: 13, color: "#1e293b" }}>{g.descricao}</div>
        <div style={{ fontSize: 11, color: "#94a3b8", marginTop: 2 }}>
          {g.data} · {g.tipo}{g.ambiente ? ` · ${g.ambiente}` : ""}{g.fornecedor ? ` · ${g.fornecedor}` : ""}{g.qtd ? ` · ${g.qtd}` : ""}
        </div>
      </div>
      <div style={{ fontWeight: 700, fontSize: 14, color: "#1e293b", flexShrink: 0 }}>{fmt(g.valor)}</div>
      <button style={btnDanger} onClick={() => onRemover(g.id)}>✕</button>
    </div>
  ));
}

function PedreiroBlock({ orcamento, pagamentos, onSetOrcamento, onAdd, onRem, formAberto, setFormAberto }) {
  const [editandoOrc, setEditandoOrc] = useState(false);
  const [inputOrc, setInputOrc] = useState("");
  const pago = pagamentos.reduce((s, g) => s + g.valor, 0);
  const saldoPed = orcamento - pago;
  const pct = orcamento > 0 ? pago / orcamento : 0;
  const aberto = formAberto === "ped-pag";

  function salvarOrcamento() {
    const v = parseFloat(inputOrc.replace(",", "."));
    if (!isNaN(v) && v >= 0) onSetOrcamento(v);
    setEditandoOrc(false);
  }

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>
      {/* Card orçamento contratado */}
      <div style={{ background: "#fff7ed", border: "1.5px solid #fdba74", borderRadius: 12, padding: "16px 18px" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
          <div>
            <div style={{ fontSize: 11, fontWeight: 700, color: "#ea580c", textTransform: "uppercase", letterSpacing: 1 }}>💼 Orçamento Contratado</div>
            {editandoOrc ? (
              <div style={{ display: "flex", gap: 8, alignItems: "center", marginTop: 6 }}>
                <input
                  autoFocus
                  style={{ ...inputStyle, width: 160, fontSize: 16, fontWeight: 700 }}
                  placeholder="0,00"
                  value={inputOrc}
                  onChange={e => setInputOrc(e.target.value)}
                  onKeyDown={e => { if (e.key === "Enter") salvarOrcamento(); if (e.key === "Escape") setEditandoOrc(false); }}
                />
                <button style={btnPrimary} onClick={salvarOrcamento}>OK</button>
                <button style={btnSec} onClick={() => setEditandoOrc(false)}>✕</button>
              </div>
            ) : (
              <div style={{ display: "flex", alignItems: "center", gap: 10, marginTop: 4 }}>
                <span style={{ fontSize: 22, fontWeight: 800, color: "#1e293b" }}>{fmt(orcamento)}</span>
                <button
                  onClick={() => { setInputOrc(orcamento > 0 ? String(orcamento) : ""); setEditandoOrc(true); }}
                  style={{ background: "#fed7aa", color: "#9a3412", border: "none", borderRadius: 6, padding: "3px 10px", fontSize: 11, fontWeight: 700, cursor: "pointer" }}
                >✏ Editar</button>
              </div>
            )}
          </div>
          <div style={{ textAlign: "right" }}>
            <div style={{ fontSize: 11, color: "#64748b" }}>Pago até agora</div>
            <div style={{ fontWeight: 800, fontSize: 18, color: "#1e293b" }}>{fmt(pago)}</div>
          </div>
        </div>
        {orcamento > 0 && (
          <>
            <ProgressBar pct={pct} />
            <div style={{ display: "flex", justifyContent: "space-between", fontSize: 12, marginTop: 8 }}>
              <span style={{ color: "#64748b" }}>{(pct * 100).toFixed(1)}% pago</span>
              <span style={{ fontWeight: 700, color: saldoPed >= 0 ? "#16a34a" : "#dc2626" }}>
                {saldoPed >= 0 ? `Restam ${fmt(saldoPed)}` : `Excedeu ${fmt(Math.abs(saldoPed))}`}
              </span>
            </div>
          </>
        )}
      </div>

      {/* Pagamentos realizados */}
      <div style={{ border: "1.5px solid #e2e8f0", borderRadius: 12, overflow: "hidden" }}>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "12px 16px", background: "#fafafa", borderBottom: (aberto || pagamentos.length > 0) ? "1px solid #e5e7eb" : "none" }}>
          <div style={{ fontWeight: 700, fontSize: 13, color: "#475569" }}>💳 Pagamentos realizados</div>
          <button style={{ ...btnPrimary, padding: "7px 14px", fontSize: 13 }} onClick={() => setFormAberto(aberto ? null : "ped-pag")}>
            {aberto ? "✕" : "+ Registrar pagamento"}
          </button>
        </div>
        {aberto && (
          <div style={{ padding: "14px 16px", background: "#fff" }}>
            <FormGasto tipos={TIPOS_PED} onSalvar={onAdd} onCancelar={() => setFormAberto(null)} />
          </div>
        )}
        {pagamentos.length > 0 ? (
          <div style={{ padding: "0 16px 8px" }}>
            <ListaGastos gastos={pagamentos} onRemover={onRem} />
          </div>
        ) : (
          !aberto && <div style={{ textAlign: "center", color: "#94a3b8", fontSize: 13, padding: "20px 0" }}>Nenhum pagamento registrado ainda.</div>
        )}
      </div>
    </div>
  );
}

// Componente acordeão para cada seção principal
function Accordion({ id, title, icon, total, badge, cor, children, defaultOpen = true }) {
  const [open, setOpen] = useState(defaultOpen);
  return (
    <div style={{ background: "#fff", borderRadius: 14, marginTop: 16, boxShadow: "0 1px 4px rgba(0,0,0,0.08)", overflow: "hidden" }}>
      {/* Cabeçalho clicável */}
      <div
        onClick={() => setOpen(o => !o)}
        style={{ display: "flex", alignItems: "center", gap: 12, padding: "16px 22px", cursor: "pointer", userSelect: "none", borderBottom: open ? "1px solid #f1f5f9" : "none", transition: "border 0.2s" }}
      >
        <span style={{ fontSize: 22 }}>{icon}</span>
        <div style={{ flex: 1 }}>
          <div style={{ fontSize: 11, fontWeight: 700, letterSpacing: 1.2, color: "#64748b", textTransform: "uppercase" }}>{title}</div>
          <div style={{ marginTop: 5 }}><ProgressBar pct={total / ORCAMENTO_TOTAL} /></div>
        </div>
        <div style={{ textAlign: "right", marginRight: 10 }}>
          <div style={{ fontWeight: 800, fontSize: 17, color: "#1e293b" }}>{fmt(total)}</div>
          <div style={{ marginTop: 4 }}>{badge}</div>
        </div>
        {/* Setinha */}
        <div style={{ width: 28, height: 28, borderRadius: "50%", background: "#f1f5f9", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, transition: "transform 0.25s", transform: open ? "rotate(180deg)" : "rotate(0deg)" }}>
          <svg width="14" height="14" viewBox="0 0 14 14" fill="none">
            <path d="M3 5l4 4 4-4" stroke="#64748b" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/>
          </svg>
        </div>
      </div>
      {/* Conteúdo */}
      {open && <div style={{ padding: "16px 22px 20px" }}>{children}</div>}
    </div>
  );
}

export default function App() {
  const [tela,         setTela]         = useState("landing");
  const [andares,      setAndares]      = useState(ANDARES_INIT);
  const [preObra,      setPreObra]      = useState(PRE_OBRA_CATS.map(c => ({ ...c, gastos: [] })));
  const [pedreiro,     setPedreiro]     = useState(PEDREIRO_INIT);
  const [formAberto,   setFormAberto]   = useState(null);
  const [loaded,       setLoaded]       = useState(false);
  const [toast,        setToast]        = useState("");
  const [confirmClear, setConfirmClear] = useState(false);
  const [backupJson,      setBackupJson]      = useState(null);
  const [showImportModal, setShowImportModal] = useState(false);

  useEffect(() => {
    storageLoad().then(saved => {
      const data = saved || SAVED_BACKUP;
      if (data.andares) {
        const temFormatoAntigo = data.andares.length > 1 || (data.andares[0] && data.andares[0].id !== "obra");
        if (temFormatoAntigo) {
          const gastosUnificados = data.andares.flatMap(a => a.gastos || []);
          setAndares([{ ...ANDARES_INIT[0], gastos: gastosUnificados }]);
        } else {
          setAndares(data.andares);
        }
      }
      if (data.preObra) setPreObra(data.preObra);
      if (data.pedreiro) {
        const p = data.pedreiro;
        if (p.gastos && !p.pagamentos) {
          const totalAntigo = p.gastos.reduce((s, g) => s + g.valor, 0);
          setPedreiro({ ...PEDREIRO_INIT, orcamento: totalAntigo, pagamentos: [] });
        } else {
          setPedreiro(p);
        }
      }
      setLoaded(true);
    });
  }, []);

  useEffect(() => {
    if (!loaded) return;
    storageSave({ andares, preObra, pedreiro });
  }, [andares, preObra, pedreiro, loaded]);

  const totalAndares  = useMemo(() => andares.reduce((s, a) => s + a.gastos.reduce((g, x) => g + x.valor, 0), 0), [andares]);
  const totalPreObra  = useMemo(() => preObra.reduce((s, c) => s + c.gastos.reduce((g, x) => g + x.valor, 0), 0), [preObra]);
  const totalPedreiro = useMemo(() => pedreiro.pagamentos.reduce((s, g) => s + g.valor, 0), [pedreiro]);
  const totalGeral    = totalAndares + totalPreObra + totalPedreiro;
  const saldo         = ORCAMENTO_TOTAL - totalGeral;
  const pctGeral      = totalGeral / ORCAMENTO_TOTAL;

  function addGastoAndar(id, g)      { setAndares(prev => prev.map(a => a.id !== id ? a : { ...a, gastos: [...a.gastos, g] })); setFormAberto(null); }
  function remGastoAndar(aId, gId)   { setAndares(prev => prev.map(a => a.id !== aId ? a : { ...a, gastos: a.gastos.filter(g => g.id !== gId) })); }
  function addGastoPreObra(cId, g)   { setPreObra(prev => prev.map(c => c.id !== cId ? c : { ...c, gastos: [...c.gastos, g] })); setFormAberto(null); }
  function remGastoPreObra(cId, gId) { setPreObra(prev => prev.map(c => c.id !== cId ? c : { ...c, gastos: c.gastos.filter(g => g.id !== gId) })); }
  function addGastoPedreiro(g)   { setPedreiro(prev => ({ ...prev, pagamentos: [...prev.pagamentos, g] })); setFormAberto(null); }
  function remGastoPedreiro(gId) { setPedreiro(prev => ({ ...prev, pagamentos: prev.pagamentos.filter(g => g.id !== gId) })); }
  function setOrcamentoPedreiro(v) { setPedreiro(prev => ({ ...prev, orcamento: v })); }

  async function handleClearAll() {
    await storageClear();
    setAndares(ANDARES_INIT.map(a => ({ ...a, gastos: [] })));
    setPreObra(PRE_OBRA_CATS.map(c => ({ ...c, gastos: [] })));
    setPedreiro({ ...PEDREIRO_INIT, orcamento: 0, pagamentos: [] });
    setConfirmClear(false);
    setToast("Todos os dados foram apagados");
  }

  function handleExport() {
    const payload = { andares, preObra, pedreiro, exportadoEm: new Date().toLocaleString("pt-BR") };
    setBackupJson(JSON.stringify(payload, null, 2));
  }

  function handleImportData(parsed) {
    if (parsed.andares) setAndares(parsed.andares);
    if (parsed.preObra) setPreObra(parsed.preObra);
    if (parsed.pedreiro) {
      const p = parsed.pedreiro;
      if (p.gastos && !p.pagamentos) {
        const totalAntigo = p.gastos.reduce((s, g) => s + g.valor, 0);
        setPedreiro({ ...PEDREIRO_INIT, orcamento: totalAntigo, pagamentos: [] });
      } else {
        setPedreiro(p);
      }
    }
    setShowImportModal(false);
    setToast("Backup importado com sucesso!");
  }

  // CatBlock interno (pedreiro/arquiteta) — sem acordeão próprio pois já está dentro do Accordion
  function CatBlock({ id, icon, label, gastos, tipos, onAdd, onRem, corBorda }) {
    const total = gastos.reduce((s, g) => s + g.valor, 0);
    const aberto = formAberto === id;
    return (
      <div style={{ border: `1.5px solid ${corBorda || "#e5e7eb"}`, borderRadius: 12, overflow: "hidden" }}>
        <div style={{ display: "flex", alignItems: "center", gap: 12, padding: "14px 16px", background: "#fafafa", borderBottom: aberto || gastos.length > 0 ? "1px solid #e5e7eb" : "none" }}>
          <div style={{ flex: 1 }}>
            <div style={{ fontWeight: 700, fontSize: 14, color: "#1e293b" }}>{label}</div>
          </div>
          <div style={{ textAlign: "right", marginRight: 8 }}>
            <div style={{ fontWeight: 700, fontSize: 15, color: "#1e293b" }}>{fmt(total)}</div>
            <div style={{ marginTop: 4 }}><Badge n={gastos.length} /></div>
          </div>
          <button style={{ ...btnPrimary, padding: "7px 14px", fontSize: 13 }} onClick={() => setFormAberto(aberto ? null : id)}>
            {aberto ? "✕" : "+ Lançar"}
          </button>
        </div>
        {aberto && <div style={{ padding: "14px 16px", background: "#fff" }}><FormGasto tipos={tipos} onSalvar={onAdd} onCancelar={() => setFormAberto(null)} /></div>}
        {gastos.length > 0 && <div style={{ padding: "0 16px 8px" }}><ListaGastos gastos={gastos} onRemover={onRem} /></div>}
      </div>
    );
  }

  if (tela === "landing") return <LandingPage onEnter={() => setTela("app")} />;

  if (!loaded) return (
    <div style={{ fontFamily: "'Inter','Segoe UI',sans-serif", display: "flex", alignItems: "center", justifyContent: "center", minHeight: "100vh", background: "#f0f4f8", color: "#64748b", fontSize: 14 }}>
      Carregando dados...
    </div>
  );

  return (
    <div style={{ fontFamily: "'Inter','Segoe UI',sans-serif", background: "#f0f4f8", minHeight: "100vh", paddingBottom: 48 }}>
      {toast && <Toast msg={toast} onClose={() => setToast("")} />}
      {confirmClear && <ConfirmModal msg="Apagar todos os lançamentos?" onConfirm={handleClearAll} onCancel={() => setConfirmClear(false)} />}
      {backupJson && <BackupModal json={backupJson} onClose={() => setBackupJson(null)} />}
      {showImportModal && <ImportModal onImport={handleImportData} onClose={() => setShowImportModal(false)} />}

      {/* Header */}
      <div style={{ background: "linear-gradient(135deg,#1e3a5f 0%,#2e6da4 100%)", color: "#fff", padding: "24px 28px 20px" }}>
        <button
          onClick={() => setTela("landing")}
          style={{ background: "rgba(255,255,255,0.12)", border: "1.5px solid rgba(255,255,255,0.25)", color: "#fff", borderRadius: 8, padding: "5px 14px", fontSize: 12, fontWeight: 600, cursor: "pointer", marginBottom: 14, display: "inline-flex", alignItems: "center", gap: 6 }}
        >
          ← Voltar
        </button>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", flexWrap: "wrap", gap: 12, marginBottom: 16 }}>
          <div>
            <div style={{ fontSize: 22, fontWeight: 700, letterSpacing: -0.5 }}>🏠 Reforma Duplex</div>
            <div style={{ fontSize: 13, opacity: 0.7, marginTop: 4 }}>Controle de gastos em tempo real</div>
          </div>
          <div style={{ textAlign: "right" }}>
            <div style={{ fontSize: 12, opacity: 0.7 }}>Saldo disponível</div>
            <div style={{ fontSize: 22, fontWeight: 700, color: saldo >= 0 ? "#86efac" : "#fca5a5" }}>{fmt(saldo)}</div>
            <div style={{ fontSize: 12, opacity: 0.7 }}>de {fmt(ORCAMENTO_TOTAL)}</div>
          </div>
        </div>
        <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
          <button style={btnGhost} onClick={handleExport}>📋 Exportar backup</button>
          <button style={btnGhost} onClick={() => setShowImportModal(true)}>⬆ Importar backup</button>
          <button style={{ ...btnGhost, borderColor: "rgba(239,68,68,0.5)", color: "#fca5a5" }} onClick={() => setConfirmClear(true)}>🗑 Limpar tudo</button>
        </div>
      </div>

      <div style={{ maxWidth: 860, margin: "0 auto", padding: "0 16px" }}>

        {/* Cards resumo */}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 12, marginTop: 16 }}>
          {[
            { label: "Total Gasto",    value: fmt(totalGeral),    sub: `${(pctGeral*100).toFixed(1)}% do orçamento`, cor: "#2e6da4" },
            { label: "Obra",           value: fmt(totalAndares),  sub: "1º e 2º andar",  cor: "#0891b2" },
            { label: "Pedreiro",       value: fmt(totalPedreiro), sub: "Mão de obra",     cor: "#ea580c" },
            { label: "Arquiteta",      value: fmt(totalPreObra),  sub: "Honorários",      cor: "#7c3aed" },
          ].map(({ label, value, sub, cor }) => (
            <div key={label} style={{ background: "#fff", borderRadius: 14, padding: "14px 16px", boxShadow: "0 1px 4px rgba(0,0,0,0.08)", borderTop: `3px solid ${cor}` }}>
              <div style={{ fontSize: 10, fontWeight: 700, color: "#94a3b8", textTransform: "uppercase", letterSpacing: 1 }}>{label}</div>
              <div style={{ fontSize: 16, fontWeight: 800, color: "#1e293b", marginTop: 6 }}>{value}</div>
              <div style={{ fontSize: 10, color: "#64748b", marginTop: 4 }}>{sub}</div>
            </div>
          ))}
        </div>

        {/* Barra geral */}
        <div style={{ background: "#fff", borderRadius: 14, padding: "20px 22px", marginTop: 16, boxShadow: "0 1px 4px rgba(0,0,0,0.08)" }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
            <span style={{ fontWeight: 700, fontSize: 14, color: "#1e293b" }}>Progresso geral</span>
            <span style={{ fontSize: 13, color: "#64748b" }}>{(pctGeral*100).toFixed(1)}% utilizado</span>
          </div>
          <ProgressBar pct={pctGeral} />
          <div style={{ display: "flex", justifyContent: "space-between", fontSize: 12, color: "#94a3b8", marginTop: 8 }}>
            <span>Gasto: <strong style={{ color: "#1e293b" }}>{fmt(totalGeral)}</strong></span>
            <span>Saldo: <strong style={{ color: saldo >= 0 ? "#16a34a" : "#dc2626" }}>{fmt(saldo)}</strong></span>
          </div>
        </div>

        {/* PEDREIRO — orçamento + pagamentos */}
        <Accordion
          id="pedreiro"
          title="Pedreiro"
          icon="🧱"
          total={totalPedreiro}
          badge={<Badge n={pedreiro.pagamentos.length} />}
        >
          <PedreiroBlock
            orcamento={pedreiro.orcamento}
            pagamentos={pedreiro.pagamentos}
            onSetOrcamento={setOrcamentoPedreiro}
            onAdd={addGastoPedreiro}
            onRem={remGastoPedreiro}
            formAberto={formAberto}
            setFormAberto={setFormAberto}
          />
        </Accordion>

        {/* ARQUITETA — acordeão */}
        <Accordion
          id="arquiteta"
          title="Arquiteta"
          icon="📐"
          total={totalPreObra}
          badge={<Badge n={preObra.reduce((s,c) => s + c.gastos.length, 0)} />}
        >
          {preObra.map(cat => (
            <CatBlock key={cat.id} id={cat.id} icon={cat.icon} label={cat.label} gastos={cat.gastos}
              tipos={TIPOS_PRE} onAdd={g => addGastoPreObra(cat.id, g)} onRem={id => remGastoPreObra(cat.id, id)} />
          ))}
        </Accordion>

        {/* ANDARES — cada um com acordeão */}
        {andares.map(andar => {
          const total = andar.gastos.reduce((s, g) => s + g.valor, 0);
          const aberto = formAberto === andar.id;
          return (
            <Accordion
              key={andar.id}
              id={andar.id}
              title={andar.label}
              icon={andar.icon}
              total={total}
              badge={<Badge n={andar.gastos.length} />}
            >
              <button style={{ ...btnPrimary, marginBottom: aberto ? 14 : 0 }} onClick={() => setFormAberto(aberto ? null : andar.id)}>
                {aberto ? "✕ Cancelar" : "+ Novo lançamento"}
              </button>
              {aberto && (
                <div style={{ marginTop: 14 }}>
                  <FormGasto tipos={TIPOS_ANDAR} ambientes={andar.ambientes}
                    onSalvar={g => addGastoAndar(andar.id, g)} onCancelar={() => setFormAberto(null)} />
                </div>
              )}
              {andar.gastos.length > 0 && (
                <div style={{ marginTop: aberto ? 0 : 12 }}>
                  <ListaGastos gastos={andar.gastos} onRemover={id => remGastoAndar(andar.id, id)} />
                </div>
              )}
            </Accordion>
          );
        })}

        <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 6, marginTop: 24 }}>
          <span style={{ width: 7, height: 7, borderRadius: "50%", background: "#86efac", display: "inline-block" }} />
          <p style={{ textAlign: "center", fontSize: 11, color: "#cbd5e1", margin: 0 }}>Dados salvos automaticamente · Use Exportar para fazer backups</p>
        </div>
      </div>
    </div>
  );
}
